const body = $input.first().json;
if (!body.company) throw new Error('Missing company field');
return [{ json: { company: body.company, email: body.email || '', session_id: `ci-${Date.now()}` } }];

const agentResult = $input.first().json;
const company = $('Validate Input').first().json.company;
const steps = agentResult.steps || [];
const toolsUsed = [...new Set(steps.filter(s => s.tool).map(s => s.tool))];

return [{
  json: {
    company,
    answer: agentResult.answer,
    total_steps: agentResult.total_steps,
    tools_used: toolsUsed,
    session_id: agentResult.session_id,
    timestamp: new Date().toISOString()
  }
}];

